public void CountingSort(int[] arr)
{
    if (arr.Length == 0) return;
    int maxVal = arr.Max();
    int[] count = new int[maxVal + 1];
    foreach (int x in arr) count[x]++;
    int index = 0;
    for (int i = 0; i <= maxVal; i++)
    {
        while (count[i] > 0)
        {
            arr[index++] = i;
            count[i]--;
        }
    }
}

