public void CombSort(int[] arr)
{
    int n = arr.Length;
    int gap = n;
    bool swapped = true;
    while (gap != 1 || swapped)
    {
        gap = GetNextGap(gap);
        swapped = false;
        for (int i = 0; i < n - gap; i++)
        {
            if (arr[i] > arr[i + gap])
            {
                (arr[i], arr[i + gap]) = (arr[i + gap], arr[i]);
                swapped = true;
            }
        }
    }
}

private void Flip(int[] arr, int k)
{
    Array.Reverse(arr, 0, k + 1);
