public void PancakeSort(int[] arr)
{
    int n = arr.Length;
    for (int currSize = n; currSize > 1; --currSize)
    {
        int maxIndex = Array.IndexOf(arr, arr.Take(currSize).Max());
        if (maxIndex != currSize - 1)
        {
            if (maxIndex != 0) Flip(arr, maxIndex);
            Flip(arr, currSize - 1);
        }
    }
}

public void GnomeSort(int[] arr)
{
    int index = 0;
    while (index < arr.Length)
    {
        if (index == 0) index++;
        if (arr[index] >= arr[index - 1])
        {
            index++;
        } 
        else
        {
            (arr[index], arr[index - 1]) = (arr[index - 1], arr[index]);
            index--;
        }
    }
}

public void CocktailShakerSort(int[] arr)
{
    bool swapped = true;
    int start = 0;
    int end = arr.Length - 1;
    while (swapped)
    {
        swapped = false;
        for (int i = start; i < end; ++i)
        {
            if (arr[i] > arr[i + 1])
            {
                (arr[i], arr[i + 1]) = (arr[i + 1], arr[i]);
                swapped = true;
            }
        }
        if (!swapped) break;
        swapped = false;
        --end;
        for (int i = end - 1; i >= start; --i)
        {
            if (arr[i] > arr[i + 1])
            {
                (arr[i], arr[i + 1]) = (arr[i + 1], arr[i]);
                swapped = true;
            }
        }
        ++start;
    }
}

