public class DSU
{
    private int[] parent;
    public DSU(int n)
    {
        parent = new int[n];
        for(int i = 0; i < n; i++) parent[i] = i;
    }

    public int Find(int i)
    {
        if (parent[i] == i) return i;
        return parent[i] = Find(parent[i]);
    }

    public void Unite(int i, int j)
    {
        int root_i = Find(i);
        int root_j = Find(j);
        if (root_i != root_j) parent[root_i] = root_j;
    }
}

