using System.Collections.Generic;

public List<int> SieveOfEratosthenes(int n)
{
    bool[] prime = new bool[n + 1];
    for (int i = 0; i <= n; i++) prime[i] = true;
    for (int p = 2; p * p <= n; p++)
    {
        if (prime[p])
        {
            for (int i = p * p; i <= n; i += p) prime[i] = false;
        }
    }
    var primeNumbers = new List<int>();
    for (int p = 2; p <= n; p++) if (prime[p]) primeNumbers.Add(p);
    return primeNumbers;
}

public long Power(long baseVal, long exp, long mod)
{
    long res = 1;
    baseVal %= mod;
    while (exp > 0)
    {
        if (exp % 2 == 1) res = (res * baseVal) % mod;
        exp >>= 1;
        baseVal = (baseVal * baseVal) % mod;
    }
    return res;
}

public long NCr(int n, int r)
{
    if (r < 0 || r > n) return 0;
    if (r == 0 || r == n) return 1;
    if (r > n / 2) r = n - r;
    long res = 1;
    for (int i = 1; i <= r; i++)
    {
        res = res * (n - i + 1) / i;
    }
    return res;
}

public long NPr(int n, int r)
{
    if (r < 0 || r > n) return 0;
    long res = 1;
    for (int i = 0; i < r; i++) res *= (n - i);
    return res;
}

public bool IsPalindromeNumber(int n)
{
    if (n < 0 || (n % 10 == 0 && n != 0)) return false;
    int reversedHalf = 0;
    while (n > reversedHalf)
    {
        reversedHalf = reversedHalf * 10 + n % 10;
        n /= 10;
    }
    return n == reversedHalf || n == reversedHalf / 10;
}

public int[,] MultiplyMatrices(int[,] A, int[,] B)
{
    int rA = A.GetLength(0), cA = A.GetLength(1);
    int rB = B.GetLength(0), cB = B.GetLength(1);
    if (cA != rB) throw new ArgumentException("Matrices cannot be multiplied.");
    int[,] C = new int[rA, cB];
    for (int i = 0; i < rA; i++)
        for (int j = 0; j < cB; j++)
            for (int k = 0; k < cA; k++)
                C[i, j] += A[i, k] * B[k, j];
    return C;
}

using System.Numerics;

public BigInteger Catalan(int n)
{
    // C_n = (1/(n+1)) * (2n choose n)
    return BinomialCoefficient(2 * n, n) / (n + 1);
}

private BigInteger BinomialCoefficient(int n, int k)
{
    if (k < 0 || k > n) return 0;
    if (k == 0 || k == n) return 1;
    if (k > n / 2) k = n - k;
    BigInteger res = 1;
