public List<int> RabinKarpSearch(string text, string pattern)
{
    const int d = 256;
    const int q = 101; // A prime number
    int m = pattern.Length, n = text.Length;
    int p = 0, t = 0, h = 1;
    var result = new List<int>();
    for (int i = 0; i < m - 1; i++) h = (h * d) % q;
    for (int i = 0; i < m; i++) { p = (d * p + pattern[i]) % q; t = (d * t + text[i]) % q; }
    for (int i = 0; i <= n - m; i++)
    {
        if (p == t && text.Substring(i, m) == pattern) result.Add(i);
        if (i < n - m) { t = (d * (t - text[i] * h) + text[i + m]) % q; if (t < 0) t += q; }
    }
    return result;
}

