    return n & ~(1 << i);
}

public int ToggleBit(int n, int i)
{
    return n ^ (1 << i);
}

public bool IsPowerOfTwo(int n)
{
    return n > 0 && (n & (n - 1)) == 0;
}

using System.Linq;

public int SingleNumber(int[] nums)
{
    return nums.Aggregate(0, (current, num) => current ^ num);
}

public void SwapNumbers(ref int a, ref int b)
{
    if (a == b) return;
    a ^= b;
    b ^= a;
    a ^= b;
}

public int[] SingleNumberIII(int[] nums)
{
    int xorAll = 0;
    foreach (int num in nums) xorAll ^= num;
    int rightmostSetBit = xorAll & -xorAll;
    int num1 = 0, num2 = 0;
    foreach (int num in nums)
    {
        if ((num & rightmostSetBit) != 0) num1 ^= num;
        else num2 ^= num;
    }
    return new int[] { num1, num2 };
}

public int BinaryToGray(int n)
{
    return n ^ (n >> 1);
}

public uint ReverseBits(uint n)
{
    uint res = 0;
    for (int i = 0; i < 32; i++)
    {
        res <<= 1;
        if ((n & 1) == 1) res |= 1;
        n >>= 1;
    }
    return res;
}

public int GetSum(int a, int b)
{
    while (b != 0)
    {
        int carry = (a & b) << 1;
        a = a ^ b;
        b = carry;
    }
    return a;
}

using System;

public int FindPosition(int n)
{
    if (n == 0 || (n & (n - 1)) != 0) return -1;
    return (int)Math.Log(n, 2) + 1;
}

public int CountFlips(int a, int b)
{
    int xorVal = a ^ b;
    int count = 0;
    while (xorVal > 0)
    {
        xorVal &= (xorVal - 1);
        count++;
    }
    return count;
}

using System.Collections.Generic;

public int[] TwoSum(int[] nums, int target)
{
    var map = new Dictionary<int, int>();
    for (int i = 0; i < nums.Length; ++i)
    {
        int complement = target - nums[i];
        if (map.ContainsKey(complement))
        {
            return new int[] { map[complement], i };
        }
        map[nums[i]] = i;
    }
    return null;
}

using System;

public int MaxSubArraySum(int[] nums)
{
    int maxSoFar = nums[0];
    int maxEndingHere = nums[0];
    for (int i = 1; i < nums.Length; i++)
    {
        maxEndingHere = Math.Max(nums[i], maxEndingHere + nums[i]);
        maxSoFar = Math.Max(maxSoFar, maxEndingHere);
    }
    return maxSoFar;
}

using System.Collections.Generic;

public int[] MaxSlidingWindow(int[] nums, int k)
{
    var result = new List<int>();
    var dq = new LinkedList<int>();
    for (int i = 0; i < nums.Length; ++i)
    {
        if (dq.Count > 0 && dq.First.Value == i - k) dq.RemoveFirst();
        while (dq.Count > 0 && nums[dq.Last.Value] < nums[i]) dq.RemoveLast();
        dq.AddLast(i);
        if (i >= k - 1) result.Add(nums[dq.First.Value]);
    }
    return result.ToArray();
}

