using System.Linq;

public int MinMeetingRooms(int[][] intervals)
{
    if (intervals.Length == 0) return 0;
    var startTimes = intervals.Select(i => i[0]).OrderBy(t => t).ToArray();
    var endTimes = intervals.Select(i => i[1]).OrderBy(t => t).ToArray();
    int rooms = 0, endPointer = 0;
    for(int startPointer = 0; startPointer < intervals.Length; startPointer++)
    {
        if(startTimes[startPointer] < endTimes[endPointer]) rooms++;
        else endPointer++;
    }
    return rooms;
}

public void NextPermutation(int[] nums)
{
    int i = nums.Length - 2;
    while (i >= 0 && nums[i + 1] <= nums[i]) i--;
    if (i >= 0)
    {
        int j = nums.Length - 1;
        while (nums[j] <= nums[i]) j--;
        (nums[i], nums[j]) = (nums[j], nums[i]);
    }
    Array.Reverse(nums, i + 1, nums.Length - (i + 1));
}

public void SortColors(int[] nums)
{
    int low = 0, mid = 0, high = nums.Length - 1;
    while (mid <= high)
    {
        if (nums[mid] == 0) (nums[low++], nums[mid++]) = (nums[mid], nums[low]);
        else if (nums[mid] == 1) mid++;
        else (nums[mid], nums[high--]) = (nums[high], nums[mid]);
    }
}

public int Josephus(int n, int k)
{
    if (n == 1) return 0;
    return (Josephus(n - 1, k) + k) % n;
}

using System;

public int[] ReservoirSampling(int[] stream, int k)
{
    int[] reservoir = new int[k];
    Array.Copy(stream, reservoir, k);
    Random rand = new Random();
    for (int i = k; i < stream.Length; i++)
    {
        int j = rand.Next(i + 1);
        if (j < k) reservoir[j] = stream[i];
    }
    return reservoir;
}

public int MajorityElement(int[] nums)
{
    int count = 0, candidate = 0;
    foreach (int num in nums)
    {
        if (count == 0) candidate = num;
        count += (num == candidate) ? 1 : -1;
    }
    return candidate;
}

using System.Collections.Generic;

private void TopologicalSortUtil(int v, List<int>[] adj, bool[] visited, Stack<int> stack)
{
    visited[v] = true;
    foreach (var i in adj[v])
        if (!visited[i]) TopologicalSortUtil(i, adj, visited, stack);
    stack.Push(v);
}

public int[] TopologicalSort(int V, List<int>[] adj)
{
    Stack<int> stack = new Stack<int>();
    bool[] visited = new bool[V];
    for (int i = 0; i < V; i++)
        if (!visited[i]) TopologicalSortUtil(i, adj, visited, stack);
    return stack.ToArray();
}

public class ListNode { public int val; public ListNode next; }

public bool HasCycle(ListNode head)
{
    ListNode slow = head, fast = head;
    while (fast != null && fast.next != null)
    {
        slow = slow.next;
        fast = fast.next.next;
        if (slow == fast) return true;
    }
    return false;
}

using System.Collections.Generic;

public int[][] FloodFill(int[][] image, int sr, int sc, int newColor)
{
    int oldColor = image[sr][sc];
    if (oldColor == newColor) return image;
    int R = image.Length, C = image[0].Length;
    var q = new Queue<(int, int)>();
    q.Enqueue((sr, sc));
    image[sr][sc] = newColor;
    int[] dr = {0, 0, 1, -1}, dc = {1, -1, 0, 0};
    while (q.Count > 0)
    {
        var (r, c) = q.Dequeue();
        for (int i = 0; i < 4; i++)
        {
            int nr = r + dr[i], nc = c + dc[i];
            if (nr >= 0 && nr < R && nc >= 0 && nc < C && image[nr][nc] == oldColor)
            {
                image[nr][nc] = newColor;
                q.Enqueue((nr, nc));
            }
        }
    }
    return image;
}

using System;

public int Trap(int[] height)
{
    if (height.Length == 0) return 0;
    int left = 0, right = height.Length - 1;
    int leftMax = 0, rightMax = 0, ans = 0;
    while (left < right)
    {
        if (height[left] < height[right])
        {
            if (height[left] >= leftMax) leftMax = height[left];
            else ans += leftMax - height[left];
            left++;
        } 
        else
        {
            if (height[right] >= rightMax) rightMax = height[right];
            else ans += rightMax - height[right];
            right--;
        }
    }
    return ans;
}

/* The Knows API is defined in the parent class Relation.
      bool Knows(int a, int b); */

public class Solution : Relation {
    public int FindCelebrity(int n) {
        int candidate = 0;
        for (int i = 1; i < n; i++) {
            if (Knows(candidate, i)) {
                candidate = i;
            }
        }
        for (int i = 0; i < n; i++) {
            if (i != candidate && (Knows(candidate, i) || !Knows(i, candidate))) {
                return -1;
            }
        }
        return candidate;
    }
}
